class Solution {
public:
    int reachNumber(int target) {
        int steps = 0;
        int currentPosition = 0;
        while (currentPosition != target) {
            steps++;
            currentPosition += steps;
            if (currentPosition > target) {
                currentPosition -= steps;
            }
        }
        return steps;
    }
};
```
